INSERT INTO public.reviews (id, user_id, developer_id, developer_name, author_name, rating, title, comment, experience_type, unit_type, is_anonymous, is_verified, attachment_urls, created_at, status, reviewed_by, reviewed_at, verification_level, category_ratings, completion_level) VALUES ('efbd9da1-fc50-4aa3-9cfa-bc03bc68e32a', '6c1146d9-ed9a-4a23-b7e5-081caeaf1eed', 'palm-hills', 'Palm Hills Developments', '1 LOCATION', 3, 'SO BIG VILLA ', 'Finding a home that actually matches its description is rare, but walking into this villa changed everything. Before I arrived, I was expecting just another standard property, but the moment I stepped inside, the sheer scale of the space took my breath away. It isn''t just a house; it’s an expansive, massive living experience. Now, I finally understand what a truly spacious villa feels like—it’s absolutely incredible!', 'form.exp_investor', 'VILLA ', false, false, '{}', '2026-03-28 07:52:54.296975+00', 'approved', '6c1146d9-ed9a-4a23-b7e5-081caeaf1eed', '2026-04-06 07:35:09.992+00', 'none', '{}', 'rating_only');
