INSERT INTO public.reviews (id, user_id, developer_id, developer_name, author_name, rating, title, comment, experience_type, unit_type, is_anonymous, is_verified, attachment_urls, created_at, status, reviewed_by, reviewed_at, verification_level, category_ratings, completion_level) VALUES ('4f841390-ce53-48b6-8577-0729e1ff540b', '443f883e-f407-46ab-a4c7-821dae3fb64b', 'palm-hills', 'Palm Hills Developments', 'HR 1 LOCATION', 5, 'great  design ', 'I had a great experience working with R8ESTATE. The service was professional and exceeded my expectations.', 'form.exp_agent', 'villa ', false, false, '{}', '2026-03-24 20:12:04.986785+00', 'approved', '6c1146d9-ed9a-4a23-b7e5-081caeaf1eed', '2026-04-06 07:35:18.848+00', 'none', '{}', 'rating_only');
